pub fn save(&self, path: &Path) -> Result<(), CalError> {
        let bytes = bincode::serialize(self).map_err(|e| CalError::Serialization(e.to_string()))?;
        let mut file = std::fs::File::create(path)?;
        file.write_all(&bytes)?;
        Ok(())
    }
